#!/usr/bin/env python3
"""
Bug #2618: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['normalization', 'reduce_mean_first_axis'], ['broadcast', 'cumsum_last_axis'], ['attention', 'matmul_4d_batch'], ['attention', 'matmul_4d_batch'], ['constant', 'cast_fp32_int32_roundtrip'], ['broadcast', 'neg_unary']]
Dependencies: numpy jax
Run         : python unique_2618.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("0300000000000000"), dtype=np.int64).reshape([1])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_rmf_red = jnp.mean(x, axis=(0,), keepdims=True)
    n0_rmf_out = x + n0_rmf_red
    n100_cs_out = jnp.cumsum(n0_rmf_out, axis=int(_w0.flat[0]))
    n200_mm4d_out = jnp.matmul(n100_cs_out, _w1)
    n300_mm4d_out = jnp.matmul(n200_mm4d_out, _w2)
    n400_cfir_ab = jnp.abs(n300_mm4d_out)
    n400_cfir_ce = jnp.ceil(n400_cfir_ab)
    n400_cfir_ci = n400_cfir_ce.astype(np.int32)
    n400_cfir_cf = n400_cfir_ci.astype(np.float32)
    n400_cfir_out = n400_cfir_cf * n300_mm4d_out
    n500_neg__a = -n400_cfir_out
    n500_neg__out = n500_neg__a * n400_cfir_out
    return jnp.asarray(n500_neg__out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
